// n8n Code Node: Token Velocity & Repetition Metric Auditor
const payload = $('Webhook Trigger').first().json.body || {};
const agentOut = items[0].json || {};

// Derive execution telemetry from the supervisor's intermediate steps when available
const intermediate = agentOut.intermediateSteps || [];
const executionHistory = (agentOut.execution_steps && agentOut.execution_steps.length)
  ? agentOut.execution_steps
  : intermediate.map((step) => ({
      tokens_used: (step.observation || '').length,
      internal_thought: (step.action && step.action.log) || (step.action && step.action.toolInput) || '',
    }));

let loopDetected = false;
let violationReason = "";

const MAX_STEPS = (payload.chaos_parameters && payload.chaos_parameters.max_turn_depth) || 10;
const MAX_TOKEN_BURNOUT = (payload.chaos_parameters && payload.chaos_parameters.max_token_velocity_allocation) || 25000;

// 1. Evaluate Absolute Limits
if (executionHistory.length >= MAX_STEPS) {
    loopDetected = true;
    violationReason = "EXCEEDED_MAX_LOGICAL_STEPS";
}

// 2. Compute Total Session Token Burn Rate
const totalTokens = executionHistory.reduce((sum, turn) => sum + (turn.tokens_used || 0), 0);
if (totalTokens > MAX_TOKEN_BURNOUT) {
    loopDetected = true;
    violationReason = "TOKEN_VELOCITY_CRITICAL_BREACH";
}

// 3. Evaluate Semantic Thought Identity Loops
const thoughts = executionHistory.map((turn) => String(turn.internal_thought || "").trim().toLowerCase());
const uniqueThoughts = new Set(thoughts);

if (thoughts.length >= 4 && uniqueThoughts.size <= (thoughts.length / 2)) {
    loopDetected = true;
    violationReason = "SEMANTIC_REPETITION_TRAP";
}

return [{
    json: {
        target_swarm_id: (payload.meta && payload.meta.organization_id) || (payload.target_agent_config && payload.target_agent_config.name) || null,
        supervisor_report: agentOut.output || null,
        metrics: {
            total_steps_executed: executionHistory.length,
            total_tokens_consumed: totalTokens,
            semantic_uniqueness_ratio: thoughts.length ? (uniqueThoughts.size / thoughts.length) : 1
        },
        security_status: loopDetected ? "COMPROMISED" : "RESILIENT",
        vulnerability_profile: loopDetected ? violationReason : "NONE"
    }
}];
